#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int value;
    struct Node* next;
} Node;

typedef struct LinkedList {
    Node* head;
    Node* tail;
} LinkedList;

Node* createNode(int value) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    newNode->value = value;
    newNode->next = NULL;
    return newNode;
}

void insertAtEnd(LinkedList* list, int value) {
    Node* newNode = createNode(value);
    if (list->head == NULL) {
        list->head = newNode;
        list->tail = newNode;
    } else {
        list->tail->next = newNode;
        list->tail = newNode;
    }
}

void printValues(LinkedList* list) {
    Node* cur = list->head;
    while (cur != NULL) {
        printf("%d", cur->value);
        if (cur->next != NULL) printf(" ");
        cur = cur->next;
    }
    printf("\n");
}

int main() {
    int T; scanf("%d", &T);
    while (T--) {
        LinkedList list = {NULL, NULL};
        int N; scanf("%d", &N);
        for (int i = 0; i < N; ++i) {
            int v; scanf("%d", &v);
            insertAtEnd(&list, v);
        }
        printValues(&list);
        // free memory (optional for contest)
        Node* cur = list.head;
        while (cur) {
            Node* nxt = cur->next;
            free(cur);
            cur = nxt;
        }
    }
    return 0;
}

