#include <bits/stdc++.h>
using namespace std;

struct Node {
    int value;
    Node* next;
    Node(int v) : value(v), next(nullptr) {}
};

struct LinkedList {
    Node* head = nullptr;
    Node* tail = nullptr;
    void insertAtEnd(int v) {
        Node* nd = new Node(v);
        if (!head) {
            head = tail = nd;
        } else {
            tail->next = nd;
            tail = nd;
        }
    }
    void print() const {
        for (Node* cur = head; cur; cur = cur->next) {
            cout << cur->value;
            if (cur->next) cout << ' ';
        }
        cout << '\n';
    }
    ~LinkedList() {
        while (head) {
            Node* nxt = head->next;
            delete head;
            head = nxt;
        }
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; cin >> T;
    while (T--) {
        int N; cin >> N;
        LinkedList lst;
        for (int i = 0; i < N; ++i) {
            int v; cin >> v;
            lst.insertAtEnd(v);
        }
        lst.print();
    }
    return 0;
}

code.Java:
import java.util.*;

class Node {
    int value;
    Node next;
    Node(int v) { value = v; }
}

class LinkedList {
    Node head = null;
    Node tail = null;
    void insertAtEnd(int v) {
        Node nd = new Node(v);
        if (head == null) {
            head = tail = nd;
        } else {
            tail.next = nd;
            tail = nd;
        }
    }
    StringBuilder toStringBuilder() {
        StringBuilder sb = new StringBuilder();
        for (Node cur = head; cur != null; cur = cur.next) {
            sb.append(cur.value);
            if (cur.next != null) sb.append(' ');
        }
        return sb;
    }
}

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            LinkedList list = new LinkedList();
            for (int i = 0; i < N; ++i) {
                int v = sc.nextInt();
                list.insertAtEnd(v);
            }
            System.out.println(list.toStringBuilder().toString());
        }
        sc.close();
    }
}

